class Solution {
	public:
		int lengthOfLIS(vector<int>& nums) {
			vector<int> dp; dp.resize(nums.size());
			list<int> list;
			set<int> set;
			int max_len = 1;
			for (int i = 1; i < nums.size(); i++) {
				if (nums[i] > nums[i-1]) {
					list.push_back(nums[i]);
					set.insert(nums[i]);
					max_len = max(max_len, (int)list.size());
				}
			}
			return max_len;
		}
};

